const person = $json.person;

if (!person) {
  return [];
}

// Get current job
const currentJob = (person.employment_history || []).find(job => job.current === true) || {};

// Build clean output
return [
  {
    full_name: person.name || null,
    first_name: person.first_name || null,
    last_name: person.last_name || null,
    linkedin_url: person.linkedin_url || null,
    title: person.title || null,
    headline: person.headline || null,
    email: person.email || null,
    email_status: person.email_status || null,
    city: person.city || null,
    state: person.state || null,
    country: person.country || null,
    seniority: person.seniority || null,

    current_company: currentJob.organization_name || null,
    current_role: currentJob.title || null,
    current_role_start_date: currentJob.start_date || null,

    total_experience_count: (person.employment_history || []).length,

    organization_name: person.organization?.name || null,
    organization_industry: person.organization?.industry || null,
    organization_employee_count: person.organization?.estimated_num_employees || null,
    organization_website: person.organization?.website_url || null,
    organization_linkedin: person.organization?.linkedin_url || null,

    organization_technologies: person.organization?.technology_names || []
  }
];

// Collect all profiles dynamically
const profiles = items.map(item => item.json);

// Safe value helper
const safe = (val) => {
  if (!val) return "N/A";
  return val;
};

// Generate dynamic cards
const cards = profiles.map(profile => {

  const techStack = (profile.organization_technologies || [])
    .map(tech => `<span class="tech">${tech}</span>`)
    .join("");

  return `
    <div class="card">
      <div class="header">
        <div class="name">${safe(profile.full_name)}</div>
        <div class="role">${safe(profile.title)}</div>
        <div class="headline">${safe(profile.headline)}</div>
      </div>

      <div class="section">
        <div><strong>Email:</strong> ${safe(profile.email)} (${safe(profile.email_status)})</div>
        <div><strong>Location:</strong> ${safe(profile.city)}, ${safe(profile.state)}, ${safe(profile.country)}</div>
        <div><strong>Seniority:</strong> ${safe(profile.seniority)}</div>
        <div><strong>Total Experience:</strong> ${safe(profile.total_experience_count)} roles</div>
      </div>

      <div class="section">
        <div><strong>Current Company:</strong> ${safe(profile.current_company)}</div>
        <div><strong>Current Role:</strong> ${safe(profile.current_role)}</div>
        <div><strong>Start Date:</strong> ${safe(profile.current_role_start_date)}</div>
      </div>

      <div class="section">
        <div><strong>Industry:</strong> ${safe(profile.organization_industry)}</div>
        <div><strong>Employees:</strong> ${safe(profile.organization_employee_count)}</div>
        <div><strong>Website:</strong> <a href="${safe(profile.organization_website)}" target="_blank">${safe(profile.organization_website)}</a></div>
        <div><strong>LinkedIn:</strong> <a href="${safe(profile.linkedin_url)}" target="_blank">View Profile</a></div>
      </div>

      <div class="section">
        <strong>Technology Stack:</strong>
        <div class="tech-container">
          ${techStack || "N/A"}
        </div>
      </div>
    </div>
  `;
}).join("");


// Final HTML page
const html = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<title>Candidate Profiles</title>
<style>
body {
  font-family: 'Segoe UI', sans-serif;
  background: #f4f6f9;
  padding: 40px;
}
.card {
  background: #ffffff;
  padding: 25px;
  margin-bottom: 30px;
  border-radius: 14px;
  box-shadow: 0 6px 18px rgba(0,0,0,0.08);
}
.header {
  margin-bottom: 15px;
}
.name {
  font-size: 22px;
  font-weight: 600;
}
.role {
  color: #444;
  margin-top: 4px;
}
.headline {
  font-size: 14px;
  color: #777;
  margin-top: 6px;
}
.section {
  margin-top: 18px;
  font-size: 14px;
}
.tech-container {
  margin-top: 10px;
}
.tech {
  display: inline-block;
  background: #eef2ff;
  padding: 6px 10px;
  margin: 4px;
  border-radius: 6px;
  font-size: 12px;
}
a {
  color: #3b82f6;
  text-decoration: none;
}
a:hover {
  text-decoration: underline;
}
</style>
</head>
<body>
<h2>Candidate Profiles</h2>
${cards}
</body>
</html>
`;

return [
  {
    json: {
      html: html
    }
  }
];
